import React, { useEffect, useState } from 'react';
import axios from 'axios';
import { BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer } from 'recharts';
import { useAuth } from '../../context/AuthContext';

export default function HodDashboard() {
  const { user } = useAuth();
  const [data, setData] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    axios.get('/api/hod/stats').then(res => { setData(res.data); setLoading(false); }).catch(() => setLoading(false));
  }, []);

  if (loading) return <div className="loading-screen"><div className="spinner"></div></div>;
  if (!data) return <div className="empty-state"><div className="empty-icon">⚠️</div><div className="empty-text">Failed to load</div></div>;

  const { stats, studentsBySem, subjectsBySem } = data;
  const semData = studentsBySem.map(s => ({ name: `Sem ${s._id}`, students: s.count }));
  const subData = subjectsBySem.map(s => ({ name: `Sem ${s._id}`, subjects: s.count }));

  return (
    <div>
      <div className="info-box" style={{ marginBottom: 20 }}>
        🏢 Department: <strong>{user?.department?.name}</strong> ({user?.department?.code})
      </div>

      <div className="stats-grid">
        <div className="stat-card blue"><div className="stat-icon">👨‍🎓</div><div><div className="stat-value">{stats.totalStudents}</div><div className="stat-label">Students</div></div></div>
        <div className="stat-card green"><div className="stat-icon">👩‍🏫</div><div><div className="stat-value">{stats.totalFaculty}</div><div className="stat-label">Faculty</div></div></div>
        <div className="stat-card cyan"><div className="stat-icon">📚</div><div><div className="stat-value">{stats.totalSubjects}</div><div className="stat-label">Subjects</div></div></div>
        <div className="stat-card yellow"><div className="stat-icon">⏳</div><div><div className="stat-value">{stats.pendingMarks}</div><div className="stat-label">Pending Approvals</div></div></div>
        <div className="stat-card green"><div className="stat-icon">✅</div><div><div className="stat-value">{stats.approvedMarks}</div><div className="stat-label">Approved Marks</div></div></div>
      </div>

      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 20 }}>
        <div className="card">
          <div className="card-header"><span className="card-title">Students per Semester</span></div>
          <div className="card-body">
            {semData.length ? (
              <div className="chart-container">
                <ResponsiveContainer width="100%" height="100%">
                  <BarChart data={semData}><XAxis dataKey="name" tick={{ fontSize: 11 }} /><YAxis allowDecimals={false} /><Tooltip /><Bar dataKey="students" fill="#1a56db" radius={[4,4,0,0]} /></BarChart>
                </ResponsiveContainer>
              </div>
            ) : <div className="empty-state"><div className="empty-text">No student data</div></div>}
          </div>
        </div>

        <div className="card">
          <div className="card-header"><span className="card-title">Subjects per Semester</span></div>
          <div className="card-body">
            {subData.length ? (
              <div className="chart-container">
                <ResponsiveContainer width="100%" height="100%">
                  <BarChart data={subData}><XAxis dataKey="name" tick={{ fontSize: 11 }} /><YAxis allowDecimals={false} /><Tooltip /><Bar dataKey="subjects" fill="#10b981" radius={[4,4,0,0]} /></BarChart>
                </ResponsiveContainer>
              </div>
            ) : <div className="empty-state"><div className="empty-text">No subject data</div></div>}
          </div>
        </div>
      </div>
    </div>
  );
}
